/// for `non_shared + value_length`.
pub fn decode_entry(input: &[u8]) -> Option<(&[u8], u32, u32, u32)> {
    let (rest, shared, non_shared, value_length) = match input {
        [b0, b1, b2, rest @ ..] if (*b0 | *b1 | *b2) < 128 => {
            (rest, *b0 as u32, *b1 as u32, *b2 as u32)
