            let (r3, value_length) = get_varint32_ptr(r2)?;
            (r3, shared, non_shared, value_length)
        }
    };

    let needed = non_shared.checked_add(value_length)? as usize;
    (rest.len() >= needed).then_some((rest, shared, non_shared, value_length))
